from fastapi import FastAPI
import asyncio

app = FastAPI()

@app.get("/async")
async def async_route():
    await asyncio.sleep(0.1)  # non-blocking
    return {"type": "async"}

@app.get("/sync")
def sync_route():
    import time
    time.sleep(0.1)  # blocking but safe (threadpool)
    return {"type": "sync"}

import threading
from fastapi import FastAPI

app = FastAPI()

@app.get("/sync")
def sync_handler():
    # Runs in threadpool thread
    return {"thread": threading.current_thread().name}

@app.get("/async")
async def async_handler():
    # Runs on main event loop thread
    return {"thread": threading.current_thread().name}

